import logging

# Set up the logger before importing anything else from this package
logging.getLogger().setLevel(logging.INFO)
if not logging.getLogger().hasHandlers():
    handler = logging.StreamHandler()
    formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')
    handler.setFormatter(formatter)
    logging.getLogger().addHandler(handler)

from azure.functions import QueueMessage
from datetime import datetime, timezone

from collabgpt_check_subscriptions.classes import SubscriptionCache
from collabgpt_check_subscriptions.functions import assess_diff

from shared.slack import slack_logging
from shared.mixpanel import track_event


@slack_logging
def main(msg: QueueMessage) -> None:
    now = datetime.now(tz=timezone.utc)
    sub_info = msg.get_json()
        # sub_info contains the following fields:
        #   i: the ordinal number of this request in the batch from its timed-function invocation
        #   of: the total number of requests in the batch from the timed-function invocation
        #   at: the invocation time of the timed-function whose batch this request is from
        #   sub_id: the subscription ID
        #   sub: the subscription details from the user actions API
        #   new_data: the current state of the entity the subscription is about (this having changed was the actual trigger)
        #   diff: the diff between the last entity snapshot and new_data
        #   past_notifications: any notification previously sent about this subscription
    sub_id = sub_info['sub_id']
    org = sub_info['sub']['organisation']
    logging.info('Subscription checker function triggered at %s for subscription assessment %s of the %s from the %s batch.',
                 now.isoformat(), sub_info['i'], sub_info['of'], sub_info['at'])

    # Data sources
    sub_closure_cache = SubscriptionCache('TO_CLOSE', org)
    subs_to_close = sub_closure_cache.get_entries()
    past_notifications_cache = SubscriptionCache('PAST_NOTIFICATIONS', org)

    # Make the subscription agent examine the changes and if necessary notify and decide to schedule closures
    response = assess_diff(sub_info, requests_per_minute_limit=21700)  ### 70% of current model RPM (vorai-gpt-5-nano-live) ###

    # A good response is a dict with cols 'conditions_are_met', 'covered_before', 'description_of_data_change', 'this_is_the_last_notification'
    if err := response.get('error'):
        raise type(err[1])(f'The Subscription Agent invocation for subscription {sub_id} failed. Error: {err[1]}')
    else:
        properties = dict(
            organisation=org,
            distinct_id=sub_info['sub']['createdByUserId'],
            sub_id=sub_id,
            entity_id=sub_info['sub']['entityId'],
            entity_type=sub_info['sub']['entityType'],
            created_time=sub_info['sub']['createdAtTimestamp']
        )

        if notification := response.get('description_of_data_change'):
            past_notifications_cache.set_entries({f'{sub_id}::{now.isoformat().replace(':', '')}': notification})
            track_event('subscription_notification_sent', properties)
            logging.info('Sent notification for: %s', properties)

        if response.get('this_is_the_last_notification'):
            if sub_id in subs_to_close:
                logging.warning('A notification for subscription %s was sent out despite the previous notification '
                                'having already been deemed final (the sub was already scheduled for closure).', sub_id)
            else:
                sub_closure_cache.set_entries({sub_id: now.isoformat()})
                track_event('subscription_scheduled_for_closure', properties)
                logging.info('Scheduled for closure: %s', properties)


